#!/usr/bin/env node
// Docs-drift check (issue #227, part 2): asserts README.md's auto-generated CLI
// reference block matches the CURRENT `cipher-brain --help` output byte-for-byte.
//
// The `HELP` template literal in src/cli.ts (the flag/behavior reference every
// user and MCP-driving agent reads) has drifted from README.md in the past
// (issue #40) — new flags/behavior landed in HELP without the docs being
// updated to match. This makes that class of drift a CI failure instead of a
// hope: the README carries the LITERAL --help text between two marker comments,
// and this script fails the build the moment the two disagree.
//
// Run standalone: `node scripts/check-help-docs.mjs` (fails non-zero + prints a
// diff on drift). `--write` regenerates the marker block in place instead of
// failing — run that after intentionally changing HELP, review the diff, and
// commit it.
//
// Runs the CLI straight off src/*.ts (bin/cipher-brain.mjs + the dev
// type-stripping flags — see scripts/dev-node-flags.mjs / #63), NOT the built
// dist/ bundle: HELP is a source-level string, so checking the source directly
// means this catches drift immediately, with no `npm run build` step required
// first (unlike scripts/cli-smoke.sh, which specifically exists to compare
// dist against source and so needs dist/ built).
//
// HELP interpolates one machine-specific path (`${IDENTITY}`, under the keygen
// section) that resolves through CIPHER_BRAIN_HOME/the OS home directory — left
// alone, the committed doc would only match on whichever machine generated it.
// FIXED_HOME below pins that to a fixed, obviously-synthetic path so the
// comparison is identical on every contributor's machine and every CI runner
// (ubuntu-latest + macos-latest, per .github/workflows/ci.yml).

import { spawnSync } from 'node:child_process';
import { mkdtempSync, readFileSync, rmSync, writeFileSync } from 'node:fs';
import { tmpdir } from 'node:os';
import { dirname, join } from 'node:path';
import { fileURLToPath } from 'node:url';
import { DEV_ARGS } from './dev-node-flags.mjs';

const HERE = dirname(fileURLToPath(import.meta.url));
const ROOT = join(HERE, '..');
const BIN = join(ROOT, 'bin', 'cipher-brain.mjs');
const README = join(ROOT, 'README.md');
const FIXED_HOME = '/home/user/.cipher-brain'; // synthetic — see header comment above

const MARKER_START = '<!-- HELP-START: auto-generated by scripts/check-help-docs.mjs — do not edit by hand -->';
const MARKER_END = '<!-- HELP-END -->';

const WRITE = process.argv.includes('--write');

function fail(msg) {
  console.error(`[FAIL] ${msg}`);
  process.exitCode = 1;
}

function getActualHelp() {
  const result = spawnSync('node', [...DEV_ARGS, BIN, '--help'], {
    cwd: ROOT,
    env: { ...process.env, CIPHER_BRAIN_HOME: FIXED_HOME },
    encoding: 'utf8',
  });
  if (result.status !== 0) {
    fail(`'cipher-brain --help' exited ${result.status}\n${result.stderr}`);
    process.exit(1);
  }
  // printMascot() writes to stderr only (src/cli.ts) — stdout is HELP alone.
  return result.stdout.replace(/\r\n/g, '\n').replace(/\n+$/, '');
}

// Extracts the block between the two markers AND unwraps its ```text fence,
// so the caller gets exactly the text --help printed, nothing else.
function extractDocHelp(readme) {
  const startIdx = readme.indexOf(MARKER_START);
  const endIdx = readme.indexOf(MARKER_END);
  if (startIdx === -1 || endIdx === -1 || endIdx < startIdx) {
    return { error: `README.md is missing the ${MARKER_START} / ${MARKER_END} marker pair` };
  }
  if (readme.indexOf(MARKER_START, startIdx + 1) !== -1 || readme.indexOf(MARKER_END, endIdx + 1) !== -1) {
    return { error: 'README.md has more than one HELP-START/HELP-END marker — remove the duplicate before comparing' };
  }
  const inner = readme
    .slice(startIdx + MARKER_START.length, endIdx)
    .replace(/\r\n/g, '\n')
    .trim();
  const fenced = inner.match(/^```text\n([\s\S]*?)\n```$/);
  if (!fenced) {
    return { error: 'the README.md marker block is not a single ```text fenced code block — cannot compare' };
  }
  return { text: fenced[1], startIdx, endIdx };
}

function printDiff(expected, actual) {
  const tmp = mkdtempSync(join(tmpdir(), 'cb-help-docs-'));
  const expectedFile = join(tmp, 'readme-help.txt');
  const actualFile = join(tmp, 'actual-help.txt');
  writeFileSync(expectedFile, `${expected}\n`);
  writeFileSync(actualFile, `${actual}\n`);
  const diff = spawnSync(
    'diff',
    ['-u', '--label', 'README.md (committed)', '--label', 'cipher-brain --help (actual)', expectedFile, actualFile],
    {
      encoding: 'utf8',
    },
  );
  console.error(diff.stdout || diff.stderr || '(diff produced no output)');
  rmSync(tmp, { recursive: true, force: true });
}

function writeDocHelp(readme, actualHelp, startIdx, endIdx) {
  const before = readme.slice(0, startIdx + MARKER_START.length);
  const after = readme.slice(endIdx);
  const block = `\n\n\`\`\`text\n${actualHelp}\n\`\`\`\n\n`;
  writeFileSync(README, before + block + after);
}

const actualHelp = getActualHelp();
const readme = readFileSync(README, 'utf8');
const doc = extractDocHelp(readme);

if (doc.error) {
  fail(doc.error);
  console.error(
    'Add the marker pair (see README.md "CLI reference" section) around a ```text fenced block, then re-run.',
  );
  process.exit(1);
}

if (doc.text === actualHelp) {
  console.log('[PASS] README.md CLI reference matches `cipher-brain --help` output');
  process.exit(0);
}

if (WRITE) {
  writeDocHelp(readme, actualHelp, doc.startIdx, doc.endIdx);
  console.log('[FIXED] README.md CLI reference regenerated from `cipher-brain --help` — review the diff and commit it');
  process.exit(0);
}

fail('README.md CLI reference is out of date with `cipher-brain --help` (issue #227)');
console.error('Run `node scripts/check-help-docs.mjs --write` to regenerate it, then commit the diff.\n');
printDiff(doc.text, actualHelp);
process.exit(1);
